class Solution {
public:
    string reversePrefix(string word, char ch) {
        int idx = word.find(ch);
        if (idx == string::npos) return word;
        string prefix = word.substr(0, idx + 1);
        string suffix = word.substr(idx + 1);
        string result = "";
        for (int i = prefix.size() - 1; i >= 0; --i) result += prefix[i];
        for (char c : suffix) result += c;
        return result;
    }
};
```

